import React, {useState} from 'react';


function msgBox(){

    return (
        <div className="msgBox">
            <div className="message-received">Olá</div>
            <div className="message-received">Tudo bem?</div>
            <div className="message-sent">Não</div>
            <div className="message-received">Então?</div>
            <div className="message-received">😭</div>
            <div className="message-sent">Don't cry 😭😭😭😭😭😭</div>
        </div>
    );
}

export default msgBox;
